import React from "../jsx-runtime"; import type { OverviewMetrics } from "../data/types"; import { compact, money, percent } from "../utils/format";
interface KpiGridProps { metrics:OverviewMetrics; }
export default function KpiGrid({metrics}:KpiGridProps){ const items=[{label:"Enterprise risk",value:`${metrics.riskIndex}/100`,delta:"Protected model",tone:metrics.riskIndex>70?"danger":"good"},{label:"Active incidents",value:String(metrics.activeIncidents),delta:`${metrics.criticalIncidents} critical`,tone:metrics.criticalIncidents?"warning":"good"},{label:"Protected assets",value:compact(metrics.protectedAssets),delta:`${percent(metrics.averageHealth)} avg. health`,tone:"good"},{label:"Estimated exposure",value:money(metrics.estimatedExposure),delta:"Model-weighted",tone:"neutral"}]; return <section className="kpi-grid">{items.map(item=><article className={`kpi-card ${item.tone}`}><div className="kpi-label">{item.label}<span>•••</span></div><strong>{item.value}</strong><small>{item.delta}</small><div className="spark-bars"><i></i><i></i><i></i><i></i><i></i><i></i></div></article>)}</section>; }
